 41→    public int JogVel { get => _jogVel; set { _jogVel = value; OnPropertyChanged(); } }
 42→    public int ActPos { get => _actPos; set { _actPos = value; OnPropertyChanged(); } }
 43→    public int ActVel { get => _actVel; set { _actVel = value; OnPropertyChanged(); } }
 44→    public ushort ErrCode { get => _errCode; set { _errCode = value; OnPropertyChanged(); } }
 45→    public ushort ActPosDeg { get => _actPosDeg; set { _actPosDeg = value; OnPropertyChanged(); } }
 46→
 47→    // Heartbeat 카운터 (MW500: bit0~7=카운터, bit8=PC_READY)
 48→    private byte _heartbeatCount;
 49→
 50→    // PLC 상태 (MW501 파싱)
 51→    private bool _plcCommOk, _plcEmoActive, _plcServoErr, _plcWdTimeout, _plcRun;
 52→    private byte _plcHeartbeat;
 53→
 54→    public bool PlcCommOk { get => _plcCommOk; set { _plcCommOk = value; OnPropertyChanged(); } }
 55→    public bool PlcEmoActive { get => _plcEmoActive; set { _plcEmoActive = value; OnPropertyChanged(); } }
 56→    public bool PlcServoErr { get => _plcServoErr; set { _plcServoErr = value; OnPropertyChanged(); } }
 57→    public bool PlcWdTimeout { get => _plcWdTimeout; set { _plcWdTimeout = value; OnPropertyChanged(); } }
 58→    public bool PlcRun { get => _plcRun; set { _plcRun = value; OnPropertyChanged(); } }
 59→    public byte PlcHeartbeat { get => _plcHeartbeat; set { _plcHeartbeat = value; OnPropertyChanged(); } }
 60→
 61→    // 연결 상태
 62→    private string _connectionStatus = "미연결";
 63→    private bool _isConnected;
 64→    private int _cycleMs;
