private async void BtnHome_Click(object sender, RoutedEventArgs e)
    => await _vm.HomeAsync();

private async void BtnMove_Click(object sender, RoutedEventArgs e)
    => await _vm.MoveAsync();

private async void BtnStop_Click(object sender, RoutedEventArgs e)
    => await _vm.StopAsync();

private async void BtnReset_Click(object sender, RoutedEventArgs e)
    => await _vm.ResetAsync();

// ======== JOG 버튼 (누르는 동안 ON, 떼면 OFF) ========

private async void BtnJogCw_Down(object sender, MouseButtonEventArgs e)
    => await _vm.JogStartAsync(isCw: true);

private async void BtnJogCw_Up(object sender, MouseButtonEventArgs e)
    => await _vm.JogStopAsync();

private async void BtnJogCcw_Down(object sender, MouseButtonEventArgs e)
    => await _vm.JogStartAsync(isCw: false);

private async void BtnJogCcw_Up(object sender, MouseButtonEventArgs e)
    => await _vm.JogStopAsync();

